contracts/Election.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";

contract Election is AccessControl {
    bytes32 public constant ELECTION_MANAGER_ROLE = keccak256("ELECTION_MANAGER_ROLE");

    enum ElectionState { NotStarted, Ongoing, Ended }
    ElectionState public state;

    struct Candidate {
        uint256 id;
        string name;
        string imageCID;
        uint256 voteCount;
    }

    struct Voter {
        bool isRegistered;
        bool hasVoted;
        uint256 votedCandidateId;
    }

    mapping(uint256 => Candidate) public candidates;
    uint256 public candidatesCount;

    mapping(address => Voter) public voters;
    uint256 public totalVotes;

    event CandidateAdded(uint256 indexed candidateId, string name, string imageCID);
    event VoterRegistered(address indexed voterAddress);
    event VoteCasted(address indexed voterAddress, uint256 indexed candidateId);
    event ElectionStateChanged(ElectionState newState);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ELECTION_MANAGER_ROLE, msg.sender);
        state = ElectionState.NotStarted;
    }

    modifier inState(ElectionState _state) {
        require(state == _state, "Invalid election state for this action");
        _;
    }

    function addCandidate(string memory _name, string memory _imageCID) 
        external 
        onlyRole(ELECTION_MANAGER_ROLE) 
        inState(ElectionState.NotStarted) 
    {
        candidatesCount++;
        candidates[candidatesCount] = Candidate({
            id: candidatesCount,
            name: _name,
            imageCID: _imageCID,
            voteCount: 0
        });
        emit CandidateAdded(candidatesCount, _name, _imageCID);
    }

    function registerVoter(address _voterAddress) 
        external 
        onlyRole(ELECTION_MANAGER_ROLE) 
        inState(ElectionState.NotStarted) 
    {
        require(!voters[_voterAddress].isRegistered, "Voter already registered");
        voters[_voterAddress].isRegistered = true;
        emit VoterRegistered(_voterAddress);
    }

    function startElection() external onlyRole(ELECTION_MANAGER_ROLE) inState(ElectionState.NotStarted) {
        state = ElectionState.Ongoing;
        emit ElectionStateChanged(state);
    }

    function endElection() external onlyRole(ELECTION_MANAGER_ROLE) inState(ElectionState.Ongoing) {
        state = ElectionState.Ended;
        emit ElectionStateChanged(state);
    }

    function vote(uint256 _candidateId) external inState(ElectionState.Ongoing) {
        require(voters[msg.sender].isRegistered, "Voter not registered");
        require(!voters[msg.sender].hasVoted, "Voter has already voted");
        require(_candidateId > 0 && _candidateId <= candidatesCount, "Invalid candidate ID");

        voters[msg.sender].hasVoted = true;
        voters[msg.sender].votedCandidateId = _candidateId;

        candidates[_candidateId].voteCount++;
        totalVotes++;

        emit VoteCasted(msg.sender, _candidateId);
    }

    function getCandidate(uint256 _candidateId) external view returns (Candidate memory) {
        require(_candidateId > 0 && _candidateId <= candidatesCount, "Invalid candidate ID");
        return candidates[_candidateId];
    }
}

